class MedianFinder {
private:
    priority_queue<int> maxHeap; // max heap to store the smaller half of numbers
    priority_queue<int, vector<int>, greater<int>> minHeap; // min heap to store the larger half of numbers

public:
    MedianFinder() {}

    void addNum(int num) {
        // Add num to the correct heap
        if (maxHeap.empty() || num <= maxHeap.top()) {
            maxHeap.push(num);
        } else {
            minHeap.push(num);
        }

        // Balance the heaps to ensure size difference is at most 1
        if (maxHeap.size() > minHeap.size() + 1) {
            minHeap.push(maxHeap.top());
            maxHeap.pop();
        } else if (minHeap.size() > maxHeap.size()) {
            maxHeap.push(minHeap.top());
            minHeap.pop();
        }
    }

    double findMedian() {
        // If total count is odd, return the top of max heap
        if (maxHeap.size() > minHeap.size()) {
            return (double)maxHeap.top();
        }
        // If total count is even, return the average of tops of both heaps
        return (maxHeap.top() + (double)minHeap.top()) / 2.0;
    }
};

